  ('promotion-660afcb0-moex-00118', 'promotion-660afcb0', 'promotion-660afcb0-moex-112-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於行政程序法之迴避，下列敘述何者錯誤？', '["公務員在行政程序中發現事件當事人曾為三等親內之姻親，應自行迴避", "公務員在稅務事件中發現當事人為其所厭惡之國小導師，自認執行職務有偏頗之虞，向所屬機 關自請迴避，機關認為不符應自行迴避事由，應否准之", "當事人有具體事證，足認承辦公務員執行職務有偏頗之虞，得向公務員所屬機關申請迴避", "公務員所屬機關之長官於公務員有應自行迴避之事由而不迴避，而未經當事人申請迴避時，應 依職權命其迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:52+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "143", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00119', 'promotion-660afcb0', 'promotion-660afcb0-moex-112-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '下列何者得提起訴願救濟？', '["公務人員對公務人員保障暨培訓委員會之復審決定不服", "會計師不服懲戒處分，向財政部會計師覆審委員會聲請覆審，對於該覆審決議不服", "義務人對具有行政處分性質之執行命令不服，依行政執行法聲明異議經上級機關駁回異議", "納稅義務人對於課稅處分不服，依稅捐稽徵法申請復查，對於復查決定不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:52+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "143", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00120', 'promotion-660afcb0', 'promotion-660afcb0-moex-112-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '關於訴願當事人適格之敘述，下列何者錯誤？', '["訴願人具有訴願權能，得以自己名義提起訴願者，具有當事人適格", "因行政處分遭受生活上不便利者，皆具有訴願當事人適格", "行政處分相對人以外之第三人亦可能具訴願當事人適格", "訴願當事人是否適格，受理訴願機關應依職權調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:52+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "143", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
  ('promotion-660afcb0-moex-00121', 'promotion-660afcb0', 'promotion-660afcb0-moex-112-3082b5f1', 'sub-promotion-660afcb0-04', NULL, 'single_choice', '依行政訴訟法規定，關於訴訟標的對於共同訴訟之各人，必須合一確定者，下列敘述何者錯誤？', '["他造對於共同訴訟人中之一人之行為，其效力及於全體", "共同訴訟人中之一人，生有訴訟當然停止之原因者，其效力及於全體", "共同訴訟人中之一人之行為有利益於共同訴訟人者，其效力及於全體", "共同訴訟人中之一人所為不利益於共同訴訟人之行為，其效力僅及於該人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:52+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "143", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "外交事務"}'::jsonb, NULL),
